def respond_to_objection(objection: str) -> dict:
    objection_db = {
        'too_early': {
            'patterns': ['too early', 'years away', 'not ready', 'wait'],
            'response': 'HNDL attacks are happening NOW. Data captured today will be decrypted later.',
            'evidence': 'Nation-states have bulk collection capabilities. Mosca theorem shows many deadlines have passed.',
            'action': 'Begin protecting long-lived data immediately.'
        },
        'immature_standards': {
            'patterns': ['standards', 'draft', 'not finalized', 'wait for'],
            'response': 'NIST standards are finalized. ML-KEM and ML-DSA were standardized in August 2024.',
            'evidence': 'FIPS 203 (ML-KEM) and FIPS 204 (ML-DSA) are official standards.',
            'action': 'Begin with hybrid implementations using standardized algorithms.'
        },
        'current_secure': {
            'patterns': ['still secure', 'not broken', 'works fine', 'current encryption'],
            'response': 'Current encryption WILL be broken. Shors algorithm is mathematically certain to break RSA/ECC.',
            'evidence': 'The only uncertainty is timing, not outcome. Quantum threat is inevitable.',
            'action': 'Plan for the certain transition while you have time.'
        },
        'too_expensive': {
            'patterns': ['expensive', 'cost', 'budget', 'afford'],
            'response': 'Delay makes it MORE expensive. Emergency migrations cost 2-5x more than planned ones.',
            'evidence': 'Rushed projects have higher error rates, need more resources, and face talent shortages.',
            'action': 'Start with low-cost assessment phase ($200-500K).'
        },
        'no_expertise': {
            'patterns': ['expertise', 'skills', 'knowledge', 'dont know'],
            'response': 'Nobody has deep expertise yet. Early movers build capability and competitive advantage.',
            'evidence': 'PQC talent pool is small but growing. Training resources are widely available.',
            'action': 'Invest in training core team. Partner with security vendors.'
        },
        'competitors_waiting': {
            'patterns': ['competitors', 'industry', 'everyone else', 'market'],
            'response': 'Many organizations are quietly preparing. Financial sector and government are already migrating.',
            'evidence': 'Major banks, cloud providers, and defense contractors have active PQC programs.',
            'action': 'Differentiate through security leadership.'
        }
    }

    obj_lower = objection.lower()
    best_match = None
    best_confidence = 0

    for key, data in objection_db.items():
        matches = sum(1 for p in data['patterns'] if p in obj_lower)
        confidence = matches / len(data['patterns'])
        if confidence > best_confidence:
            best_confidence = confidence
            best_match = key

    if best_match and best_confidence > 0:
        data = objection_db[best_match]
        return {
            'matched_objection': best_match,
            'response': data['response'],
            'evidence': data['evidence'],
            'action': data['action'],
            'confidence': round(best_confidence, 2)
        }

    return {
        'matched_objection': 'unknown',
        'response': 'The quantum threat is certain. The only question is timing.',
        'evidence': 'NIST, NSA, and security experts recommend immediate action.',
        'action': 'Begin with a risk assessment to understand your specific exposure.',
        'confidence': 0.0
    }

def generate_faq_document(objections: list) -> str:
    lines = ['PQC MIGRATION FAQ', '=' * 50, '']

    for i, obj in enumerate(objections, 1):
        response = respond_to_objection(obj)
        lines.append(f'Q{i}: {obj}')
        lines.append(f'A: {response["response"]}')
        lines.append(f'   Evidence: {response["evidence"]}')
        lines.append(f'   Next Step: {response["action"]}')
        lines.append('')

    return '\n'.join(lines)
